 1	import type { FC } from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import SmartLinkify from 'src/components/common/SmartLinkify';
 4	import { EMPTY_MSG } from 'src/utils/constants';
 5	
 6	import { Alert, Text, TextContent, TextVariants } from '@patternfly/react-core';
 7	
 8	const ProviderCriticalCondition: FC<{ type: string; message: string }> = ({ message, type }) => {
 9	  const { t } = useTranslation();
10	
11	  return (
12	    <Alert title={`${t('The provider is not ready')} - ${type}`} variant="danger">
13	      <TextContent className="forklift-providers-list-header__alert">
14	        <Text component={TextVariants.p}>
15	          <SmartLinkify>{message || EMPTY_MSG}</SmartLinkify>
16	          {'. '}
17	          {t('To troubleshoot, check the Forklift controller pod logs.')}
18	        </Text>
19	      </TextContent>
20	    </Alert>
21	  );
22	};
23	
24	export default ProviderCriticalCondition;

